class TestPermissionBasedAccess:
    """Test permission-based module access."""
    
    def test_admin_sees_all_modules(self):
        """Test that admin users see all modules."""
        pytest.importorskip("PyQt6")
        from ui.main_window import MainWindow, MODULE_REGISTRY
        from core.permissions import PermissionManager
        
        mock_pm = Mock(spec=PermissionManager)
        mock_pm.is_admin.return_value = True
        mock_pm.has_permission.return_value = True
        
        # Mock user
        from models import User
        mock_user = Mock(spec=User)
        mock_user.full_name = "Admin User"
        mock_user.roles = []
        mock_user.branch = None
        
        with patch('ui.main_window.permission_manager', mock_pm):
            with patch('ui.main_window.QMainWindow.__init__'):
                with patch('ui.main_window.SessionLocal'):
                    window = MainWindow.__new__(MainWindow)
                    window.user = mock_user
                    
                    # Check admin status
                    assert mock_pm.is_admin(mock_user) is True
    
    def test_non_admin_sees_permitted_modules_only(self):
        """Test that non-admin users see only permitted modules."""
        pytest.importorskip("PyQt6")
        from core.permissions import PermissionManager
        
        mock_pm = Mock(spec=PermissionManager)
        mock_pm.is_admin.return_value = False
        
        # Define which permissions the user has
        def has_perm(user, perm):
            allowed = ["users.view", "products.view"]
            return perm in allowed
        
        mock_pm.has_permission.side_effect = has_perm
        
        from models import User
        mock_user = Mock(spec=User)
        mock_user.full_name = "Regular User"
        mock_user.roles = []
        
        assert mock_pm.has_permission(mock_user, "users.view") is True
        assert mock_pm.has_permission(mock_user, "products.view") is True
        assert mock_pm.has_permission(mock_user, "admin.full_access") is False


